import {AppraisalRule} from './AppraisalRule';
import {SensorySystem} from '../../sensing/SensorySystem';
import {MotorFaultSensor} from '../../sensing/sensors/MotorFaultSensor';
import {EmotionTrace} from '../../emotion/EmotionTrace';
import {EmotionSystem} from "../../EmotionSystem";
import {EmotionPoint, RuleImpactValues} from "../../common/Types";

import parentLog from '../../log';
const log = parentLog.createChild('Appraisal.MotorFaultRule');

export {}

/**
 * @internal
 */
export class MotorFaultRule extends AppraisalRule {

    private touchSensor: MotorFaultSensor;

    constructor(name: string, parent: EmotionSystem) {
        super(name, parent);
    }

    /** @override */
    init(sensorySystem: SensorySystem) {
        this.touchSensor = <any> sensorySystem.getSensor(MotorFaultSensor.SENSOR_NAME);
        if (!this.touchSensor) {
            throw new Error(`MotorFaultSensor sensor is required, doesn't exist.`);
        }
        this.touchSensor.events.newDataEvent.on((sensorDataWrapper) => {
            log.info('Appraising data from MotorFault data:', sensorDataWrapper.sensorData);
            this.parent.jibo.analytics.track("Snuggle Occurred", { type: "Motor Fault" });
            let myTrace = new EmotionTrace([sensorDataWrapper], this, this.appraiseData(sensorDataWrapper.sensorData));
            this.events.impactTriggered.emit(myTrace);
        });
    }

    /** @override */
    appraiseData(input: any): EmotionPoint {
        log.debug(`motor fault`);
        return new EmotionPoint(RuleImpactValues.MOTOR_FAULT_VALENCE, RuleImpactValues.MOTOR_FAULT_CONFIDENCE);
    }

    dispose() {
        this.touchSensor.events.removeAllListeners();
    }

}
