/*
 *
 * Stores all installed sensors that can be used by the Appraisal system to
 * appraise how Jibo's external environment affects his emotional state
 *
 */

import {Sensor} from './sensors/Sensor';
import {EmotionSystem} from "../EmotionSystem";

import parentLog from '../log';
const log = parentLog.createChild('SensorySystem');

export {}

/**
 * @description Sensory management of Jibo's sensory inputs.
 * @namespace jibo.emotion.sensors
 * @private
 * @internal
 */
export class SensorySystem {

    /**
     * A list of the sensors involved in this emotional event.
     * @type {Map<string, Sensor>}
     * @name jibo.emotion.sensors#sensorMap
     * @private
     */
    private sensorMap = new Map<string, Sensor<any>>();

    constructor(private parent: EmotionSystem) {
      return;
    }

    /**
     * Initialize the sensory system with an array of sensors to be installed.
     * @param {Sensor[]} sensors Sensors that will be installed as part of Jibo's sensory system
     * @method jibo.emotion.sensors#init
     */
    init(sensors: Sensor<any>[]) {
        // wait until init to get jibo, parent doesn't get instance
        // until it's initialized
        sensors.forEach(sensor => {
            log.debug("initting sensor", sensor.name);
            sensor.init();
            this.sensorMap.set(sensor.name, sensor);
        });
    }

    /**
     * Returns an installed sensor of a given name if it exists
     * @param {String} name Name of sensor to get
     * @returns {Sensor<any>} The corresponding sensor
     * @method jibo.emotion.sensors#getSensor
     */
    getSensor(name: string) {
        return this.sensorMap.get(name);
    }

    dispose() {
        this.sensorMap.forEach((sensor) => {
            sensor.dispose();
        });
        // TODO: check that it will go through the map first?
        this.sensorMap.clear();
    }
}
