import {AppraisalRule} from './AppraisalRule';
import {SensorySystem} from '../../sensing/SensorySystem';
import {TouchSensor, TouchEvent} from '../../sensing/sensors/TouchSensor';
import {EmotionTrace} from '../../emotion/EmotionTrace';
import {EmotionSystem} from "../../EmotionSystem";
import {EmotionPoint, TouchTypes, RuleImpactValues} from "../../common/Types";

import parentLog from '../../log';
const log = parentLog.createChild('Appraisal.TouchRule');

export {}

/**
 * @internal
 */
export class TouchRule extends AppraisalRule {

    private touchSensor: TouchSensor;

    constructor(name: string, parent: EmotionSystem) {
        super(name, parent);
    }

    /** @override */
    init(sensorySystem: SensorySystem) {
        this.touchSensor = <any> sensorySystem.getSensor(TouchSensor.SENSOR_NAME);
        if (!this.touchSensor) {
            throw new Error(`TouchSensor sensor is required, doesn't exist.`);
        }
        this.touchSensor.events.newDataEvent.on((sensorDataWrapper) => {
            let myTrace = new EmotionTrace([sensorDataWrapper], this, this.appraiseData(sensorDataWrapper.sensorData));
            this.events.impactTriggered.emit(myTrace);
        });
    }

    /** @override */
    appraiseData(input: TouchEvent): EmotionPoint {
        if (input.type === TouchTypes.HEAD_LEFT || input.type === TouchTypes.HEAD_RIGHT) {
            log.info(`jibo had a head touch`, input.type);
            return new EmotionPoint(RuleImpactValues.HEAD_TOUCH_VALENCE, RuleImpactValues.HEAD_TOUCH_CONFIDENCE);
        }
        else if (input.type === TouchTypes.TICKLE) {
            log.info(`jibo was tickled`);
            return new EmotionPoint(RuleImpactValues.TICKLE_VALENCE, RuleImpactValues.TICKLE_CONFIDENCE);
        }
        else {
            log.error(`could not match touch input to emotion point`, input);
            return new EmotionPoint();
        }
    }

    dispose() {
        this.touchSensor.events.removeAllListeners();
    }

}
