/*
 * @fileOverview
 *
 * Serves as the primary interpreter of sensory information to affect emotional
 * states as well as the motivation system.
 *
 */

import {Event, EventContainer} from 'jibo-typed-events';
import {EmotionTrace} from '../emotion/EmotionTrace';
import {AppraisalRule} from './rules/AppraisalRule';
import {EmotionSystem} from "../EmotionSystem";
import {RuleNames} from "../common/Types";

import parentLog from '../log';
const log = parentLog.createChild('Appraisal');


export {}

/**
 * @description Events related to the appraisal system
 * @namespace jibo.emotion.appraisal.events
 * @private
 * @internal
 */
export class AppraisalEvents extends EventContainer {

    /**
     * An event triggered whenever when Jibo's emotions should be repositioned.
     * For example, if Jibo's sensors have detected some new change, Jibo needs
     * to interpret those events.
     * @type {Event}
     * @name jibo.emotion.appraisal.events#impactTriggered
     */
    impactTriggered = new Event<EmotionTrace>('Impact triggered!');
}

/**
 * @description The system which registers and manages incoming sensory inputs
 * against appraisal rules to determine if and how they should impact Jibo's internal
 * emotional state.
 * @namespace jibo.emotion.appraisal
 * @internal
 * @private
 */
export class AppraisalSystem {

    /**
     * The events that the system can use.
     * @type {jibo.emotion.appraisal.events}
     * @name jibo.emotion.appraisal#events
     */
    public events = new AppraisalEvents();
    /**
     * A set of rules that the system relies on to generate emotional impact.
     * @type {Set<AppraisalRule>}
     * @name jibo.emotion.appraisal#_rules
     * @private
     */
    public rules = new Map<RuleNames, AppraisalRule>();
    private parent: EmotionSystem;

    /** @override */
    constructor(parent: EmotionSystem) {
        this.parent = parent;
    }

    init(rules: AppraisalRule[]) {
        rules.forEach(rule => {
            this.rules.set(RuleNames[rule.name], rule);
        });
        this._registerRules();
    }

    /**
     * Cleans up and disconnects all allocated resources.
     * @method jibo.emotion.appraisal#dispose
     */
    dispose() {
        this.events.removeAllListeners();
    }

    /**
     * Takes all the rules and registers them on the system.
     * @name jibo.emotion.appraisal#_registerRules
     * @private
     */
    private _registerRules(): void {
        this.rules.forEach((rule) => {
            rule.events.impactTriggered.on((emotionTrace) => {
                //log.debug('Impact triggered was: ', emotionTrace.emotionalImpact.valence, emotionTrace.emotionalImpact.confidence);
                //log.debug('Appraised by', emotionTrace.appraisalRule.name);
                // log.debug(`Impact triggered was: ${emotionTrace.emotionalImpact.valence}, ${emotionTrace.emotionalImpact.confidence} appraised by: ${emotionTrace.appraisalRule.name}`);
                // Temporarily just aggregate and pass the information through.
                this.events.impactTriggered.emit(emotionTrace);
            });
        });
    }
}
