import {AppraisalRule} from './AppraisalRule';
import {SensorySystem} from '../../sensing/SensorySystem';
import {MimSensor} from '../../sensing/sensors/MimSensor';
import {EmotionTrace} from '../../emotion/EmotionTrace';
import {EmotionSystem} from "../../EmotionSystem";
import {EmotionPoint, RuleImpactValues} from "../../common/Types";

import parentLog from '../../log';
const log = parentLog.createChild('Appraisal.MIMRule');

export {}

/**
 * @internal
 */
export class MimRule extends AppraisalRule {

    private mimSensor: MimSensor;

    constructor(name: string, parent: EmotionSystem) {
        super(name, parent);
    }

    /** @override */
    init(sensorySystem: SensorySystem) {
        this.mimSensor = sensorySystem.getSensor(MimSensor.SENSOR_NAME);
        if (!this.mimSensor) {
            throw new Error(`MimSensor is required, doesn't exist.`);
        }
        this.mimSensor.events.newDataEvent.on((sensorDataWrapper) => {
            log.debug("event data", sensorDataWrapper);
            let myTrace = new EmotionTrace([sensorDataWrapper], this, this.appraiseData(sensorDataWrapper.sensorData));
            this.events.impactTriggered.emit(myTrace);
        });
    }

    /** @override */
    appraiseData(mimState): EmotionPoint {
        // Any error from the MIM should make Jibo less confident.
        return new EmotionPoint(RuleImpactValues.MIM_ERROR_VALENCE, RuleImpactValues.MIM_ERROR_CONFIDENCE);
    }

    dispose() {
        this.mimSensor.events.removeAllListeners();
    }

}
